mapper.select:
select
si.survey_instance_id as surveyInstanceId,
si.survey_template_id as surveyTemplateId,
st.name as templateName,
si.responder_user_id as responderUserId,
u.full_name as employeeName,
u.email as email,
si.scheduled_at as scheduledAt,
si.status as status,
si.created_at as createdAt
from survey_instances si
join survey_templates st
on st.survey_template_id = si.survey_template_id
and st.company_id = si.company_id
left join users u
on u.user_id = si.responder_user_id
where si.company_id = #{companyId,jdbcType=VARCHAR}


    and si.survey_template_id = #{templateId,jdbcType=VARCHAR}



    and si.status = #{status,jdbcType=VARCHAR}



    and si.scheduled_at >= #{startDate,jdbcType=TIMESTAMP}



    and si.scheduled_at <= #{endDate,jdbcType=TIMESTAMP}



    and si.responder_user_id = #{responderUserId,jdbcType=VARCHAR}


order by coalesce(si.sent_at, si.scheduled_at, si.created_at) desc
limit #{limit,jdbcType=INTEGER}
offset #{offset,jdbcType=INTEGER}

select count(*)
from survey_instances si
where si.company_id = #{companyId,jdbcType=VARCHAR}


    and si.survey_template_id = #{templateId,jdbcType=VARCHAR}



    and si.status = #{status,jdbcType=VARCHAR}



    and si.scheduled_at >= #{startDate,jdbcType=TIMESTAMP}



    and si.scheduled_at <= #{endDate,jdbcType=TIMESTAMP}



    and si.responder_user_id = #{responderUserId,jdbcType=VARCHAR}

select si.survey_instance_id as surveyInstanceId, si.survey_template_id as surveyTemplateId, st.name as templateName, si.responder_user_id as responderUserId, si.status as status, si.scheduled_at as scheduledAt from survey_instances si join survey_templates st on st.survey_template_id = si.survey_template_id and st.company_id = si.company_id where si.company_id = #{companyId,jdbcType=VARCHAR} and si.survey_instance_id = #{instanceId,jdbcType=VARCHAR}
and si.responder_user_id = #{responderUserId,jdbcType=VARCHAR}
limit 1

select count(*)
from survey_instances
where company_id = #{companyId,jdbcType=VARCHAR}
and status in ('SENT', 'SCHEDULED', 'COMPLETED', 'EXPIRED')

    and survey_template_id = #{templateId,jdbcType=VARCHAR}


    and coalesce(sent_at, scheduled_at, created_at) >= #{startDate,jdbcType=TIMESTAMP}


    and coalesce(sent_at, scheduled_at, created_at) <= #{endDate,jdbcType=TIMESTAMP}

